@import "tailwindcss";

@theme {
  /* palette (mined, ranked by usage) */
  --color-neutral-100: #efefef;
  --color-neutral-200: #dddddd;
  --color-neutral-300: #cfcfcf;
  --color-neutral-400: #bfbfbf;
  --color-neutral-500: #abafba;
  --color-neutral-600: #8f94a3;
  --color-neutral-700: #73798c;
  --color-neutral-800: #5c6170;
  --color-neutral-900: #454954;
  --color-neutral-950: #292c32;
  --color-deep-blue: #0d0e11;
  --color-pale-blue: #fcfcfd;
  --color-blue: #8b7cff;
  --color-yellow: #d29922;
  --color-deep-blue-2: #061434;
  --color-blue-2: #5865f2;
  --color-deep-purple: #2d0e36;
  --color-deep-blue-3: #060522;
  --color-red: #f2330d;
  --color-blue-3: #314062;
  --color-cyan: #8fc5ff;
  --color-blue-4: #434e6f;

  /* inferred semantic roles (each maps to a distinct mined value) */
  --color-canvas: #292c32;
  --color-ink: #efefef;
  --color-text-muted: #bfbfbf;
  --color-surface: #454954;
  --color-hairline: #5c6170;
  --color-accent: #0d0e11;
  --color-accent-2: #fcfcfd;
  --color-accent-3: #8b7cff;

  --font-sans: "DM Sans", ui-sans-serif, system-ui, sans-serif;
  --font-mono: "JetBrains Mono", ui-monospace, monospace;

  --text-xs: 0.5rem;
  --text-sm: 0.625rem;
  --text-base: 0.8125rem;
  --text-lg: 0.856875rem;
  --text-xl: 0.875rem;
  --text-2xl: 0.9rem;
  --text-3xl: 0.9375rem;
  --text-4xl: 1rem;
  --text-5xl: 1.25rem;
  --text-6xl: 1.285625rem;
  --text-7xl: 1.5rem;
  --text-8xl: 2.25rem;

  --font-weight-normal: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;
  --font-weight-extrabold: 800;
  --font-weight-black: 900;

  /* line-heights, sorted tight -> loose */
  --leading-none: 1.11;
  --leading-tight: 1.33;
  --leading-snug: 1.43;
  --leading-normal: 1.5;
  --leading-relaxed: 1.56;
  --leading-loose: 1.6;
  --leading-looser: 1.71;
  --leading-loosest: 1.75;

  /* letter-spacing, sorted tight -> wide */
  --tracking-tightest: .01rem;

  --radius-sm: .3125rem;
  --radius-md: 7px;
  --radius-lg: 10px;
  --radius-xl: 14px;
  --radius-2xl: 16px;
  --radius-3xl: 20px;
  --radius-4xl: 26px;

  /* shadows, sorted by blur */
  --shadow-sm: 0 18px 56px #0000002e;
  --shadow-md: 0 18px 54px #00000024;
  --shadow-lg: 0 0 #0000;

  --breakpoint-sm: 29.6875rem;
  --breakpoint-md: 31.25rem;
  --breakpoint-lg: 32rem;
  --breakpoint-xl: 40rem;
  --breakpoint-2xl: 48rem;
  --breakpoint-3xl: 54rem;
  --breakpoint-4xl: 64rem;
  --breakpoint-5xl: 80rem;

  /* most-used spacing values on the source site (px): 1, 2, 3, 4, 5, 6, 7, 8, 9, 16, 20, 80 */
}

/* dark-mode values mined from the source (native token names) */
@media (prefers-color-scheme: dark) {
  :root {
    --tw-border-style: none;
    --tw-gradient-position: to top in oklab;
    --tw-gradient-from: #1b1d22;
    --tw-gradient-via: var(--color-dark-900);
    --tw-gradient-to: color-mix(in oklab,var(--color-dark-850)30%,transparent);
    --tw-shadow: 0px 10px 28px 0px var(--tw-shadow-color,#0006);
    --tw-shadow-color: var(--color-black);
    --tw-ring-color: var(--color-dark-200);
    --tw-ring-offset-color: var(--color-dark-800);
    --tw-drop-shadow: drop-shadow(0 2px 4px #ffffff80);
    --tw-prose-body: var(--tw-prose-invert-body);
    --tw-prose-headings: var(--tw-prose-invert-headings);
    --tw-prose-lead: var(--tw-prose-invert-lead);
    --tw-prose-links: var(--tw-prose-invert-links);
    --tw-prose-bold: var(--tw-prose-invert-bold);
    --tw-prose-counters: var(--tw-prose-invert-counters);
    --tw-prose-bullets: var(--tw-prose-invert-bullets);
    --tw-prose-hr: var(--tw-prose-invert-hr);
    --tw-prose-quotes: var(--tw-prose-invert-quotes);
    --tw-prose-quote-borders: var(--tw-prose-invert-quote-borders);
    --tw-prose-captions: var(--tw-prose-invert-captions);
    --tw-prose-kbd: var(--tw-prose-invert-kbd);
    --tw-prose-kbd-shadows: var(--tw-prose-invert-kbd-shadows);
    --tw-prose-code: var(--tw-prose-invert-code);
    --tw-prose-pre-code: var(--tw-prose-invert-pre-code);
    --tw-prose-pre-bg: var(--tw-prose-invert-pre-bg);
    --tw-prose-th-borders: var(--tw-prose-invert-th-borders);
    --tw-prose-td-borders: var(--tw-prose-invert-td-borders);
  }
}

